#ifndef RMSNORM_H2048_KERNEL_H_
#define RMSNORM_H2048_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

// Launch RMSNorm for hidden_size = 2048, BF16 input/output.
cudaError_t launch_rmsnorm_h2048_bf16(
    const __nv_bfloat16* hidden_states,  // [B, 2048]
    const __nv_bfloat16* weight,         // [2048]
    __nv_bfloat16* output,               // [B, 2048]
    int64_t batch_size,
    cudaStream_t stream);

#endif  // RMSNORM_H2048_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

#ifndef __CUDA_ARCH__
#define __CUDA_ARCH__ 0
#endif

static __device__ __forceinline__ float warp_reduce_sum(float v) {
  unsigned mask = 0xffffffffu;
  v += __shfl_down_sync(mask, v, 16);
  v += __shfl_down_sync(mask, v, 8);
  v += __shfl_down_sync(mask, v, 4);
  v += __shfl_down_sync(mask, v, 2);
  v += __shfl_down_sync(mask, v, 1);
  return v;
}

template<int BLOCK_THREADS>
static __device__ __forceinline__ float block_reduce_sum(float v) {
  static_assert((BLOCK_THREADS % 32) == 0, "BLOCK_THREADS must be multiple of warp size");
  constexpr int WARPS = BLOCK_THREADS / 32;
  __shared__ float warp_sums[WARPS];
  __shared__ float block_sum;

  int lane = threadIdx.x & 31;
  int warp = threadIdx.x >> 5;

  float wsum = warp_reduce_sum(v);
  if (lane == 0) warp_sums[warp] = wsum;
  __syncthreads();

  if (warp == 0) {
    float t = (lane < WARPS) ? warp_sums[lane] : 0.0f;
    t = warp_reduce_sum(t);
    if (lane == 0) block_sum = t;
  }
  __syncthreads();
  return block_sum;
}

static __device__ __forceinline__ __nv_bfloat162 ld_bf162(const __nv_bfloat16* p) {
  // Assumes 4-byte alignment; for contiguous BF16 tensors base is aligned and we only access even indices.
  return *reinterpret_cast<const __nv_bfloat162*>(p);
}

static __device__ __forceinline__ void st_bf162(__nv_bfloat16* p, __nv_bfloat162 v) {
  *reinterpret_cast<__nv_bfloat162*>(p) = v;
}

// One block per row, 256 threads.
// Each thread handles 8 elements (4 bf16x2 vector loads) => 256 * 8 = 2048.
__global__ void rmsnorm_h2048_kernel_bf16(
    const __nv_bfloat16* __restrict__ x,  // [B, 2048]
    const __nv_bfloat16* __restrict__ w,  // [2048]
    __nv_bfloat16* __restrict__ y,        // [B, 2048]
    int64_t batch_size) {

  constexpr int H = 2048;
  constexpr float EPS = 1e-6f;
  constexpr int BLOCK = 256;

  int row = (int)blockIdx.x;
  if ((int64_t)row >= batch_size) return;

  const __nv_bfloat16* xrow = x + (int64_t)row * H;
  __nv_bfloat16* yrow = y + (int64_t)row * H;

  int base = threadIdx.x * 8;

  float sumsq = 0.0f;

  // Accumulate sum of squares in FP32 (matches reference which does mean in FP32).
#pragma unroll
  for (int i = 0; i < 8; i += 2) {
    int col = base + i;  // even
    __nv_bfloat162 xv2 = ld_bf162(xrow + col);
    float2 xf2 = __bfloat1622float2(xv2);
    sumsq = fmaf(xf2.x, xf2.x, sumsq);
    sumsq = fmaf(xf2.y, xf2.y, sumsq);
  }

  float total_sumsq = block_reduce_sum<BLOCK>(sumsq);
  float inv_rms = rsqrtf(total_sumsq * (1.0f / (float)H) + EPS);

  // Apply normalization and weight, write BF16.
#pragma unroll
  for (int i = 0; i < 8; i += 2) {
    int col = base + i;
    __nv_bfloat162 xv2 = ld_bf162(xrow + col);
    __nv_bfloat162 wv2 = ld_bf162(w + col);

    float2 xf2 = __bfloat1622float2(xv2);
    float2 wf2 = __bfloat1622float2(wv2);

    float2 yf2;
    yf2.x = (xf2.x * inv_rms) * wf2.x;
    yf2.y = (xf2.y * inv_rms) * wf2.y;

    st_bf162(yrow + col, __float22bfloat162_rn(yf2));
  }
}

cudaError_t launch_rmsnorm_h2048_bf16(
    const __nv_bfloat16* hidden_states,
    const __nv_bfloat16* weight,
    __nv_bfloat16* output,
    int64_t batch_size,
    cudaStream_t stream) {

  if (batch_size <= 0) return cudaSuccess;

  dim3 block(256, 1, 1);
  dim3 grid((unsigned)batch_size, 1, 1);

  rmsnorm_h2048_kernel_bf16<<<grid, block, 0, stream>>>(
      hidden_states, weight, output, batch_size);

  return cudaGetLastError();
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include "kernel.h"

static inline void check_cuda_contig(const torch::Tensor& t, const char* name) {
  TORCH_CHECK(t.defined(), name, " must be defined");
  TORCH_CHECK(t.device().is_cuda(), name, " must be a CUDA tensor");
  TORCH_CHECK(t.is_contiguous(), name, " must be contiguous");
}

static torch::Tensor run_impl(const torch::Tensor& hidden_states, const torch::Tensor& weight) {
  check_cuda_contig(hidden_states, "hidden_states");
  check_cuda_contig(weight, "weight");

  TORCH_CHECK(hidden_states.dtype() == torch::kBFloat16,
              "hidden_states must be torch.bfloat16, got ", hidden_states.dtype());
  TORCH_CHECK(weight.dtype() == torch::kBFloat16,
              "weight must be torch.bfloat16, got ", weight.dtype());

  TORCH_CHECK(hidden_states.dim() == 2,
              "hidden_states must be rank-2 [batch_size, hidden_size], got dim=", hidden_states.dim());
  TORCH_CHECK(weight.dim() == 1,
              "weight must be rank-1 [hidden_size], got dim=", weight.dim());

  const int64_t batch_size = hidden_states.size(0);
  const int64_t hidden_size = hidden_states.size(1);

  TORCH_CHECK(hidden_size == 2048, "hidden_size must be 2048, got ", hidden_size);
  TORCH_CHECK(weight.size(0) == 2048, "weight must have shape [2048], got ", weight.sizes());

  TORCH_CHECK(hidden_states.get_device() == weight.get_device(),
              "hidden_states and weight must be on the same CUDA device");

  auto output = torch::empty_like(hidden_states);

  // IMPORTANT FIX: use the current PyTorch stream (not default/legacy).
  cudaStream_t stream = at::cuda::getDefaultCUDAStream(hidden_states.get_device());

  const __nv_bfloat16* x =
      reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w =
      reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr<at::BFloat16>());
  __nv_bfloat16* y =
      reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  cudaError_t err = launch_rmsnorm_h2048_bf16(x, w, y, batch_size, stream);
  TORCH_CHECK(err == cudaSuccess, "CUDA launch failed: ", cudaGetErrorString(err));

  // Catch async kernel faults deterministically.
  err = cudaStreamSynchronize(stream);
  TORCH_CHECK(err == cudaSuccess, "CUDA stream sync failed: ", cudaGetErrorString(err));

  return output;
}

// Accept both positional and kwargs: (hidden_states, weight) or hidden_states=..., weight=...
torch::Tensor run(pybind11::args args, pybind11::kwargs kwargs) {
  torch::Tensor hidden_states;
  torch::Tensor weight;

  if (kwargs) {
    if (kwargs.contains("hidden_states")) hidden_states = kwargs["hidden_states"].cast<torch::Tensor>();
    if (kwargs.contains("weight")) weight = kwargs["weight"].cast<torch::Tensor>();
  }

  if (!hidden_states.defined() || !weight.defined()) {
    TORCH_CHECK(args.size() == 2,
                "Expected either positional (hidden_states, weight) or kwargs hidden_states=..., weight=...");
    hidden_states = args[0].cast<torch::Tensor>();
    weight = args[1].cast<torch::Tensor>();
  }

  return run_impl(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function");
}
